import binascii, shutil

# Deploy HTML
html_hex = ""
html_data = binascii.unhexlify(html_hex)
with open(r"C:\mfcrm\public\index.html", "wb") as f:
    f.write(html_data)
shutil.copy(r"C:\mfcrm\public\index.html", r"C:\mfcrm\index.html")
print("OK: index.html")

# Deploy server.js
srv_hex = ""
srv_data = binascii.unhexlify(srv_hex)
with open(r"C:\mfcrm\server.js", "wb") as f:
    f.write(srv_data)
print("OK: server.js")
print("DONE!")
